from __future__ import annotations

import heapq
from dataclasses import dataclass, field
from typing import Any, Iterator


@dataclass(order=True)
class PrioritizedItem:
    """Wrapper that makes any payload comparable by priority."""

    priority: float
    sequence: int = field(compare=True)
    payload: Any = field(compare=False)


class BoundedPriorityQueue:
    """A thread-unsafe bounded priority queue backed by a min-heap.

    Items with the lowest priority value are dequeued first.
    When the queue is full, push silently drops items whose priority
    is >= the current maximum (i.e., least urgent).
    """

    def __init__(self, capacity: int) -> None:
        if capacity <= 0:
            raise ValueError(f"Capacity must be positive, got {capacity}")
        self._capacity = capacity
        self._heap: list[PrioritizedItem] = []
        self._seq = 0

    @property
    def capacity(self) -> int:
        return self._capacity

    def __len__(self) -> int:
        return len(self._heap)

    def __bool__(self) -> bool:
        return len(self._heap) > 0

    def push(self, payload: Any, priority: float) -> bool:
        """Add an item. Returns True if accepted, False if dropped."""
        item = PrioritizedItem(
            priority=priority, sequence=self._seq, payload=payload
        )
        self._seq += 1

        if len(self._heap) < self._capacity:
            heapq.heappush(self._heap, item)
            return True

        # Peek at the max item (we keep a min-heap, so max is expensive;
        # for a bounded queue we accept O(n) here).
        worst = max(self._heap)
        if item < worst:
            # Replace the worst item with the new one.
            self._heap.remove(worst)
            heapq.heapify(self._heap)
            heapq.heappush(self._heap, item)
            return True

        return False

    def pop(self) -> Any:
        """Remove and return the highest-priority (lowest value) payload."""
        if not self._heap:
            raise IndexError("pop from empty queue")
        return heapq.heappop(self._heap).payload

    def peek(self) -> Any:
        """Return the highest-priority payload without removing it."""
        if not self._heap:
            raise IndexError("peek at empty queue")
        return self._heap[0].payload

    def drain(self) -> Iterator[Any]:
        """Yield all payloads in priority order, emptying the queue."""
        while self._heap:
            yield heapq.heappop(self._heap).payload

    def __repr__(self) -> str:
        items = sorted(self._heap)
        inner = ", ".join(
            f"{it.payload!r}@{it.priority}" for it in items
        )
        return f"BoundedPriorityQueue(cap={self._capacity}, [{inner}])"
